if("serviceWorker"in navigator){window.addEventListener("load",()=>{navigator.serviceWorker.register("/sw.js").then(e=>{console.log("[TACTICAL] Service Worker registered:",e.scope),e.update(),e.onupdatefound=()=>{const r=e.installing;r.onstatechange=()=>{"installed"===r.state&&navigator.serviceWorker.controller&&console.log("[TACTICAL] New content available; please refresh.")}}}).catch(e=>{console.log("[TACTICAL] Service Worker registration failed:",e)})});let e=!1;navigator.serviceWorker.addEventListener("controllerchange",()=>{e||(window.location.reload(),e=!0)})}